<script setup lang="ts">defineProps<{modelValue?:string;label?:string;placeholder?:string;rows?:number}>();defineEmits<{"update:modelValue":[string]}>()</script><template><label class="xj-field"><span v-if="label" class="xj-label">{{label}}</span><span class="xj-input-wrap" style="height:auto;padding:10px 13px"><textarea class="xj-input" :rows="rows||4" :value="modelValue" :placeholder="placeholder" style="resize:vertical" @input="$emit('update:modelValue',($event.target as HTMLTextAreaElement).value)"></textarea></span></label></template>
